import{_ as r,o as t,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const o="/images/lekt5007.jpg",a="/images/lekt5006.jpg",l="/images/lekt5001.jpg",s="/images/lekt5002.jpg",u="/images/lekt5005.jpg",p="/images/lekt5003.jpg",b="/images/lekt5004.jpg",m="/images/lekt5008.jpg",v=JSON.parse('{"title":"Lektion 50","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion50.md","filePath":"lektionen/lektion50.md"}'),c={name:"lektionen/lektion50.md"};function g(d,e,h,k,f,q){return t(),i("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-50" tabindex="-1">Lektion 50 <a class="header-anchor" href="#lektion-50" aria-label="Permalink to &quot;Lektion 50&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>50.1. Nominalbildung: regelmäßige Steigerung</li><li>50.2. Wortliste</li><li>50.3. Übersetzungsübung</li></ul><h2 id="_50-1-nominalbildung-regelmaßige-steigerung" tabindex="-1">50.1. Nominalbildung: regelmäßige Steigerung <a class="header-anchor" href="#_50-1-nominalbildung-regelmaßige-steigerung" aria-label="Permalink to &quot;50.1. Nominalbildung: regelmäßige Steigerung&quot;">​</a></h2><p>Die regelmäßige Steigerung erfolgt im Sanskrit mit den तद्धित-Suffixen</p><ul><li>-तर (fem.: तरा) im &quot;Komparativ&quot;</li><li>तम (fem.: तमा) im &quot;Superlativ&quot;</li></ul><p>Diese Suffixe werden bei Adjektiven an den Maskulinstamm angefügt. Bei Nomina mit Stammabstufung werden sie an den schwachen Stamm angefügt, die die form hat wie vor der Endung -su des Lokativ (पञ्चमी) Plural.</p><p><img src="'+o+'" alt=""><br> Abb.: लोकस्योत्तमो गिरिः<br> Abb.: सगरमाथा = ཇོ་མོ་གླང་མ <em>=</em> 珠穆朗玛峰 = Mount Everest<br> [Bildquelle: wonker. -- <a href="http://www.flickr.com/photos/wonker/2385042288/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wonker/2385042288/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>Bedeutung:</p><p>Der &quot;Komparativ&quot; bedeutet, wenn kein verglichener Gegenstand ausgedrückt wird: &quot;ziemlich, sehr, zu&quot;:</p><blockquote><p>z.B. सुचितर 3 &quot;ziemlich rein&quot;, &quot;sehr rein&quot;, &quot;zu rein&quot;</p></blockquote><p>Wird ein verglichener Gegenstand ausgedrückt, so steht dieser im Ablativ (पञ्चमी). Komparativ + Ablativ entspricht der Steigerung mit &quot;als&quot; im Deutschen.</p><blockquote><p>z.B. देवदत्ताद्रामो धीमत्तरः = wörtl.: &quot;von Devadatta aus gesehen ist Rāma einsichtiger&quot; = &quot;Rāma ist einsichtiger als Devadatta&quot;</p></blockquote><p>Der &quot;Superlativ&quot; bedeutet, wen kein verglichener Gegenstand ausgedrückt wird: &quot;äußerst, sehr&quot;:</p><blockquote><p>z.B. सत्तम 3 (zu सन्त्) &quot;äußerst gut, sehr gut&quot;</p></blockquote><p>Wird ein verglichener Gegenstand ausgedrückt, so steht dieser im Genetiv (षष्ठी) (&quot;von&quot;, &quot;unter&quot;) und der Superlativ entspricht dem deutschen Superlativ (Höchststufe):</p><blockquote><p>z.B. द्विजानां सत्तमः = &quot;der beste der Zweimalgeborenen&quot;</p></blockquote><p>Die Suffixe -तर und -तम können nicht nur an Adjektive treten, sondern auch an Substantive, Indeklinabilia und sogar Verbalformen:</p><p>Beispiele:</p><blockquote><p>गजतम m. &quot;der beste Elefant&quot; (गज) (auch Bezeichnung Buddhas)</p><p>गोतम m. &quot;der größte Ochse&quot; (गो) oder: &quot;am reichsten an Rindern&quot;</p><p>उद् Indekl. &quot;auf&quot;, &quot;hinauf&quot; » उत्तर 3 &quot;höherer&quot; » उत्तम 3 &quot;höchster&quot;</p></blockquote><p>Treten diese Suffixe an eine Verbalform, so erscheinen sie stets in der adverbialen Form:</p><ul><li>-तराम्</li><li>-तमाम्</li></ul><p>Beispiele:</p><blockquote><p>पचतितराम् &quot;er/sie/es kocht besser&quot;</p><p>पचतितमाम् &quot;er/sie/es kocht am besten&quot;</p></blockquote><p>Diese Form haben diese Suffixe auch, wenn sie an ein Indeklinabile treten und das abgeleitete Wort adverbial gebraucht wird:</p><blockquote><p>z.B. सुतराम् (zu सु) &quot;auf bessere Weise&quot; (adverbial)</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: का पचतितमाम्<br> Lisu = 傈僳族, अरुणाचल प्रदेश<br> [Bildquelle: parrothanging. -- <a href="http://www.flickr.com/photos/biligiri/1857068925/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/biligiri/1857068925/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_50-2-wortliste" tabindex="-1">50.2. Wortliste <a class="header-anchor" href="#_50-2-wortliste" aria-label="Permalink to &quot;50.2. Wortliste&quot;">​</a></h2><p>ध्रुव 3: fest, unveränderlich</p><p>निषेक m.: Besprengung, Befruchtung, Flüssigkeit, Ejakulat, Zeremonie bei der Zeugung</p><p>पण्डित 3: klug, weise, gelehrt</p><p>मन् + अव 4Ā अवमन्यते : missachten, verachten</p><p>मन्त्रिन् 3: ratgebend ; m.: Berater, Ratsherr, Minister</p><p><img src="'+l+'" alt=""><br> Abb.: मन्त्री<br> Kapil Sibal (1948 -), Union minister in Ministry of Science and Technology and Ministry of Earth Sciences (since 2006)<br> [Bildquelle: World Economic Forum. -- <a href="http://www.flickr.com/photos/worldeconomicforum/3038328904/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldeconomicforum/3038328904/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>रहस् n.: Geheimnis, Einsamkeit</p><p>रिष् 1P रिषति 4P रिष्यति : geschädigt werden, misslingen, beschädigen</p><blockquote><p>Perf. II रिरेष, रिरिषुर्<br> Fut. रेषिष्यति<br> Pass. रिष्यते<br> Kaus. रेषयति<br> PPP रिष्ट</p></blockquote><p>लुप् 6U लुम्पति : brechen, zerstören</p><blockquote><p>Perf.  II लुलोप, लुलुपे<br> Fut. लोप्स्यति<br> Pass. लुप्यते<br> Kaus. लोपयति<br> PPP लुप्त<br> Inf. लोप्तुम्<br> Gerundiv लुप्य । लोप्य</p></blockquote><p>विधि m.: auch: Schicksal (zu विधा)</p><p>वृष् 1P वर्षति : regnen (meist mit einem कर्तृ -- einem Gott oder einer Wolke)</p><blockquote><p>Perf. II ववर्ष, ववृषुर्<br> Fut. वर्षिष्यति<br> Pass. वृष्यते<br> Kaus. वर्षयति<br> PPP वृष्ट<br> Inf. वर्षितुम्<br> Absol. वर्षित्वा । वृष्ट्वा<br> Absol.-वृष्य</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: महामेघो वर्षिष्यति<br> Ankunft des Monsun, Bangalore  ಬೆಂಗಳೂರು<br> [Bildquelle: vandan desai. -- <a href="http://www.flickr.com/photos/vandan/526579892/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/vandan/526579892/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>संयक् Adv.: richtig, wahrhaft, auf die gehörige Weise ; durchaus, vollständig</p><p>आदित्य m.: Sonne ; pl.: <a href="http://en.wikipedia.org/wiki/Aditya" target="_blank" rel="noreferrer">Āditya</a> : eine bestimmte Götterklasse</p><p><img src="'+u+'" alt=""><br> Abb.: आदित्यः<br> [Bildquelle: sunder_iyer. -- <a href="http://www.flickr.com/photos/sunder_iyer/2225272284/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/sunder_iyer/2225272284/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>सर्व 3: jeder, alle</p><p>Deklination wie यद् (Ausnahme: Nom.Akk.sg.Neutrum)</p><p>|   | Singular<br> एकवचनम् | Plural<br> बहुवचनम् | | --- | --- | --- | | Maskulinum<br> पुंस् | Neutrum<br> नपुंसकम् | Femininum<br> स्त्री | Maskulinum<br> पुंस् | Neutrum<br> नपुंसकम् | Femininum<br> स्त्री | | सर्वस् | सर्वम् | सर्वा | सर्वे | सर्वाणि | सर्वास् | | 1. Nominativ<br> १. प्रथमा | | 2. Akkusativ<br> २. द्वितीया | सर्वम् | सर्वम् | सर्वाम् | सर्वान् | सर्वाणि | सर्वास् | | 3. Instrumentalis<br> ३. तृतीया | सर्वेण | सर्वया | सर्वैस् | सर्वाभिस् | | 4. Dativ<br> ४. चतुर्थी | सर्वस्मै | सर्वस्यै | सर्वेभ्यस् | सर्वाभ्यस् | | 5. Ablativ<br> ५. पञ्चमी | सर्वस्मात् | सर्वस्यास् | सर्वेभ्यस् | सर्वाभ्यस् | | 6. Genetiv<br> ६. षष्ठी | सर्वस्य | सर्वस्यास् | सर्वेषाम् | सर्वासाम् | | 7. Lokativ<br> ७. सप्तमी | सर्वस्मिन् | सर्वस्याम् | सर्वेषु | सर्वासु |</p><p>वै : Partikel, der das vorangehende Wort betont: fürwahr, wahrlich, aber</p><p>इह Adv.: hier, hier auf Erden, hierher ; jetzt. Vor Substantiven im Lokativ (षष्ठी) gleichbedeutend mit अस्मिन्, अस्याम्</p><p>कल्प m: Satzung, Brauch, Ritual ; <a href="http://en.wikipedia.org/wiki/Kalpa_(time_unit)" target="_blank" rel="noreferrer">Weltperiode</a> (zu कॢप्)</p><p>कल्याण 3 (f.: कल्याणी) :schön</p><p><img src="'+p+'" alt=""><br> Abb.: कल्याणी<br> [Bildquelle: dhyanji. --  <a href="http://www.flickr.com/photos/dhyanji/131433199/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dhyanji/131433199/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>कु- : als Vorderglied von Komposita: schlecht</p><p><img src="'+b+'" alt=""><br> Abb.: कुनगरम्<br> धारावी, मुंबई<br> [Bildquelle: Kounosu / Wikipedia. GNU FDLicense]</p><p>चक्ष् 2Ā चष्टे 2.pl. Ā चड्ढ्वे : sehen</p><blockquote><p>Perf. चचक्षे<br> in den übrigen Tempora nicht verwendet</p></blockquote><p>चक्ष् + प्र 2Ā प्रचष्टे : erzählen, halten für, nennen</p><p>देश m.: Ort, Platz, Land, Gegend</p><h2 id="_50-3-ubersetzungsubung" tabindex="-1">50.3. Übersetzungsübung <a class="header-anchor" href="#_50-3-ubersetzungsubung" aria-label="Permalink to &quot;50.3. Übersetzungsübung&quot;">​</a></h2><p>A) Zur Wiederholung der Deklination: folgender Vers enthält alle Deklinationsformen im Singular zu गुरु m.:</p><blockquote><p>गुरुरेव गतिर्गुरुमेव भजे<br> गुरुणैव सहास्मि नमो गुरवे ।<br> न गुरोः परमं शिशुरस्मि गुरोर्<br> मतिरस्ति गुरौ मम पाहि गुरो ॥</p></blockquote><p><img src="'+m+'" alt=""><br> Abb.: गुरुमेव भजे<br> Ganeshpuri, 80 km von Mumbai (मुंबई) entfernt<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/2691860037/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/2691860037/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>B) Übersetzen Sie:</p><p>मनुस्मृति ४, १७८</p><blockquote><p>येनास्य पितरो याता<br> येन याताः पितामहाः ।<br> तेन यायात्सतां मार्गम्<br> तेन गच्छन्न रिष्यते ॥१॥</p></blockquote><p>मनुस्मृति ३, ६३</p><blockquote><p>कुविवाहैः क्रियालोपैर्<br> वेदानध्ययनेन च ।<br> कुलान्यकुलतां यान्ति<br> ब्राह्मणातिक्रमेण च ॥२॥</p></blockquote><p>मनुस्मृति ३, ६०</p><blockquote><p>संतुष्टो भार्यया भर्ता<br> भर्त्रा भार्या तथैव च ।<br> यस्मिन्नेव कुले नित्यम्<br> कल्याणं तत्र वै ध्रुवम् ॥३॥</p></blockquote><p>मनुस्मृति ३, ७५ - ७६: Über die Notwendigkeit des Opfers</p><blockquote><p>स्वाध्याये नित्ययुक्तः स्याद्<br> दैवे चैवेह कर्मणि ।<br> दैवे कर्मणि युक्तो हि<br> बिभर्तीदं चराचरम् ॥४॥<br> अग्नौ प्रास्ताहुतिः सम्यग्<br> आदित्यमुपतिष्ठते ।<br> आदित्याज्जायते वृष्टिर्<br> वृष्टेरन्नं ततः प्रजाः ॥५॥</p></blockquote><p>योगसूत्र २, १६ - १७</p><blockquote><p>हेयं दुःखमनागतम् ॥६॥<br> द्रष्टृदृश्ययोः संयोगो हेयहेतुः ॥७॥</p><p>Erklärung:<br> द्रष्टृदृश्ययोः : Gen.Lok.m.n.f.Dual (Dualdvandva)</p></blockquote><p>कौटिलीयार्थशास्त्र १, १५: Über Ratgeber des Königs</p><blockquote><p>न किंचिदवमन्येत<br> सर्वस्य शृणुयानमतम् ।<br> बालस्याप्यर्थवद्वाक्यम्<br> उपयुन्जीत पाण्डितः ॥८॥</p></blockquote><p>मनुस्मृति २, १४० - १४२: Definition von आचार्य, उपाध्याय, गुरु</p><blockquote><p>उपनीय तु यः शिष्यं<br> वेदमधापयेत्द्द्विजः ।<br> सकल्पं सरहस्यं च<br> तमाचार्यां प्रचक्षते ॥९॥</p><p>एकदेशं तु वेदस्य<br> वेदाङ्गान्यपि वा पुनः ।<br> यो ऽध्यापयति वृत्त्यर्थम्<br> उपाध्यायः स उच्यते ॥१०॥</p><p>निषेकादीनि कर्माणि<br> यः करोति यथाविधि ।<br> संभावयति चान्नेन<br> स विप्रो गुरुरुच्यते ॥११॥</p><p>Erklärungen:<br> निषेकादीनि : Nom.Akk.pl.Neutrum</p></blockquote>',80)])])}const _=r(c,[["render",g]]);export{v as __pageData,_ as default};
